"use strict";parserFactory.register("novelonomicon.com",()=>new NovelonomiconParser);class NovelonomiconParser extends Parser{constructor(){super()}async getChapterUrls(e,t){return(await this.getChapterUrlsFromMultipleTocPages(e,this.extractPartialChapterList,this.getUrlsOfTocPages,t)).reverse()}getUrlsOfTocPages(e){let t=[],r=e.querySelector(".page-nav a.last")||[...e.querySelectorAll(".page-nav a.page")].slice(-1)[0];if(null!==r){let e=parseInt(r.textContent),l=r.href,n=l.lastIndexOf("/",l.length-2);l=l.substring(0,n+1);for(let r=2;r<=e;++r)t.push(l+r+"/")}return t}extractPartialChapterList(e){return[...e.querySelectorAll(".td-block-span6 h3 a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector(".tdb_single_content .tdb-block-inner")||e.querySelector(".tdb_single_content")||e.querySelector("div.td-post-content")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".td-module-image a")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".td-category-description")]}cleanInformationNode(e){return util.removeChildElementsMatchingSelector(e,".su-spoiler"),e}}